'use strict';

const IDEMPOTENCY_MARKER = 'Memory files live in `docs/memory/{topics,sessions,snapshots}/`';

const NEW_ITEM_3 =
  '3. Memory files live in `docs/memory/{topics,sessions,snapshots}/`. Read `MEMORY.md` (compact index) at session start; read specific topic files when their topic is relevant to the current task. Do not edit `MEMORY.md` directly — it is auto-regenerated by `generate-plan.js`.';

const CHECKLIST_REPLACEMENT = [
  '- [ ] Memory files updated in `docs/memory/{topics,sessions,snapshots}/`:',
  '- [ ]   - For session learnings: `docs/memory/sessions/YYYY-MM-DD-<short-slug>.md` with `# <Title> (Session N, YYYY-MM-DD)` heading',
  '- [ ]   - For new stable knowledge: `docs/memory/topics/<topic>.md` (no date prefix in filename)',
  '- [ ]   - Do NOT edit `MEMORY.md` directly — it is auto-regenerated by `generate-plan.js`',
];

/**
 * Patch CLAUDE.md text with memory layout instructions.
 *
 * @param {string} text - Raw CLAUDE.md content
 * @returns {{ text: string, changed: boolean }}
 * @throws {Error} if patch targets not found or checklist has been customised
 */
function patchClaudeMd(text) {
  if (text.includes(IDEMPOTENCY_MARKER)) {
    return { text, changed: false };
  }

  const lines = text.split('\n');

  // Patch 1: Find "2. Read `MEMORY.md`..." and insert new item 3 after it.
  let insertIdx = -1;
  for (let i = 0; i < lines.length; i++) {
    if (/^2\.\s+Read `MEMORY\.md`/.test(lines[i])) {
      insertIdx = i;
      break;
    }
  }
  if (insertIdx === -1) {
    throw new Error(
      'CLAUDE.md Mandatory Session Startup: could not find "2. Read `MEMORY.md`" line — manual reconciliation required',
    );
  }

  lines.splice(insertIdx + 1, 0, NEW_ITEM_3);

  // Renumber subsequent numbered list items (+1 each).
  for (let i = insertIdx + 2; i < lines.length; i++) {
    const m = lines[i].match(/^(\d+)(\.\s+.*)/);
    if (!m) break;
    lines[i] = `${parseInt(m[1], 10) + 1}${m[2]}`;
  }

  // Patch 2: Find and replace the MEMORY.md checklist checkbox.
  let checklistIdx = -1;
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].startsWith('- [') && lines[i].includes('updated with new learnings')) {
      checklistIdx = i;
      break;
    }
  }
  if (checklistIdx === -1) {
    throw new Error(
      'CLAUDE.md Session Close Checklist: could not find "`MEMORY.md` updated with new learnings" checkbox — manual reconciliation required',
    );
  }

  lines.splice(checklistIdx, 1, ...CHECKLIST_REPLACEMENT);

  return { text: lines.join('\n'), changed: true };
}

const SUGGEST_MODEL_IDEMPOTENCY_MARKER = 'npm run memory:suggest-model';

const NEW_SUGGEST_MODEL_ITEM =
  '4. Before dispatching complex work to a sub-agent, run `npm run memory:suggest-model -- --task "<brief description>"` to get a model recommendation based on topic complexity in `docs/memory/`. The recommendation is `haiku` for low-complexity work or `sonnet` for medium/high; opus is never auto-recommended.';

function patchSuggestModelItem(text) {
  if (text.includes(SUGGEST_MODEL_IDEMPOTENCY_MARKER)) {
    return { text, changed: false };
  }

  const lines = text.split('\n');

  let insertIdx = -1;
  for (let i = 0; i < lines.length; i++) {
    if (/^3\.\s+Memory files live/.test(lines[i])) {
      insertIdx = i;
      break;
    }
  }
  if (insertIdx === -1) {
    throw new Error('CLAUDE.md Mandatory Session Startup: cannot find US-0178 memory item — run US-0178 patch first');
  }

  lines.splice(insertIdx + 1, 0, NEW_SUGGEST_MODEL_ITEM);

  for (let i = insertIdx + 2; i < lines.length; i++) {
    const m = lines[i].match(/^(\d+)(\.\s+.*)/);
    if (!m) break;
    lines[i] = `${parseInt(m[1], 10) + 1}${m[2]}`;
  }

  return { text: lines.join('\n'), changed: true };
}

module.exports = { patchClaudeMd, patchSuggestModelItem };
